func (s *Server) cleanupExpiredBans() {
	now := time.Now()
	s.bansMu.Lock()
	defer s.bansMu.Unlock()
	for k, v := range s.bans {
		if !v.ExpiresAt.IsZero() && now.After(v.ExpiresAt) {
			delete(s.bans, k)
		}
	}
}

