func (s *Server) handleAdminCommand(actor *Client, line string) {
	line = strings.TrimSpace(line)
	if line == "" || !strings.HasPrefix(line, "/") {
		return
	}
	parts := splitArgs(line[1:])
	if len(parts) == 0 {
		return
	}

	cmdName := strings.ToLower(parts[0])
	args := parts[1:]

	cmd, ok := s.commands()[cmdName]
	if !ok {
		s.send(actor, "ERR unknown_admin_command\n")
		return
	}
	if actor.role < cmd.MinRole {
		s.send(actor, "ERR not_authorized\n")
		return
	}
	cmd.Exec(s, actor, args)
}

func (s *Server) findTarget(idOrName string) *Client {
	if c := s.getClientByID(idOrName); c != nil {
		return c
	}
	return s.getClientByName(idOrName)
}

func canActOn(actor, target *Client) bool {
	if actor == nil || target == nil {
		return false
	}
	if actor.id == target.id {
		return false
	}
	return actor.role > target.role
}

func parseHeaderLine(s string) map[string]string {
	// expected: "HDR key=value; key=value"
	out := map[string]string{}
	s = strings.TrimSpace(s)
	if strings.HasPrefix(strings.ToUpper(s), "HDR ") {
		s = strings.TrimSpace(s[4:])
	}
	parts := strings.Split(s, ";")
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		kv := strings.SplitN(p, "=", 2)
		if len(kv) != 2 {
			continue
		}
		k := strings.ToLower(strings.TrimSpace(kv[0]))
		v := strings.TrimSpace(kv[1])
		out[k] = v
	}
	return out
}

func splitArgs(s string) []string {
	var out []string
	var cur strings.Builder
	inQuotes := false
	esc := false

	flush := func() {
		if cur.Len() > 0 {
			out = append(out, cur.String())
			cur.Reset()
		}
	}

	for _, r := range s {
		if esc {
			cur.WriteRune(r)
			esc = false
			continue
		}
		switch r {
		case '\\':
			esc = true
		case '"':
			inQuotes = !inQuotes
		case ' ', '\t':
			if inQuotes {
				cur.WriteRune(r)
			} else {
				flush()
			}
		default:
			cur.WriteRune(r)
		}
	}
	flush()
	return out
}

func parseItems(s string) (map[string]int, error) {
	out := map[string]int{}
	s = strings.TrimSpace(s)
	if s == "" {
		return nil, errors.New("empty")
	}
	pairs := strings.Split(s, ",")
	for _, p := range pairs {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		kv := strings.SplitN(p, ":", 2)
		if len(kv) != 2 {
			return nil, errors.New("bad pair")
		}
		item := strings.TrimSpace(kv[0])
		if item == "" {
			return nil, errors.New("bad item")
		}
		qty, err := strconv.Atoi(strings.TrimSpace(kv[1]))
		if err != nil || qty <= 0 {
			return nil, errors.New("bad qty")
		}
		out[item] += qty
	}
	return out, nil
}

func parseOptionalDuration(args []string) (time.Duration, int) {
	if len(args) == 0 {
		return 0, 0
	}
	d, ok := parseDurationExt(args[0])
	if !ok {
		return 0, 0
	}
	return d, 1
}

func parseDurationExt(s string) (time.Duration, bool) {
	s = strings.TrimSpace(strings.ToLower(s))
	if s == "" {
		return 0, false
	}
	if strings.HasSuffix(s, "d") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
		if err != nil || n <= 0 {
			return 0, false
		}
		return time.Duration(n) * 24 * time.Hour, true
	}
	d, err := time.ParseDuration(s)
	if err != nil || d <= 0 {
		return 0, false
	}
	return d, true
}

func safeName(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	if len(s) > 24 {
		s = s[:24]
	}
	s = strings.Map(func(r rune) rune {
		if r >= 'a' && r <= 'z' {
			return r
		}
		if r >= 'A' && r <= 'Z' {
			return r
		}
		if r >= '0' && r <= '9' {
			return r
		}
		switch r {
		case '_', '-', '.', ' ':
			return r
		default:
			return -1
		}
	}, s)
	s = strings.TrimSpace(s)
	return s
}

func safeID(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	if len(s) > 64 {
		s = s[:64]
	}
	s = strings.Map(func(r rune) rune {
		if r >= 'a' && r <= 'z' {
			return r
		}
		if r >= 'A' && r <= 'Z' {
			return r
		}
		if r >= '0' && r <= '9' {
			return r
		}
		switch r {
		case '_', '-', '.', ':':
			return r
		default:
			return -1
		}
	}, s)
	return s
}

func firstNonEmpty(a, b string) string {
	if strings.TrimSpace(a) != "" {
		return a
	}
	return b
}

func main() {
	addr := getenv("ADDR", ":7777")
	logger := log.New(os.Stdout, "[server] ", log.LstdFlags|log.Lmicroseconds)

	s := NewServer(addr, logger)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		t := time.NewTicker(1 * time.Minute)
		defer t.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-t.C:
				s.cleanupExpiredBans()
			}
		}
	}()

	if err := s.Start(ctx); err != nil {
		logger.Fatalf("server error: %v", err)
	}
}

func getenv(k, def string) string {
	if v := os.Getenv(k); strings.TrimSpace(v) != "" {
		return v
	}
	return def
}